// // This module captures the input D on the falling edge of Clk, rising edge of Clk, and when Clk is high.
module top_module(Clk, D, Qa, Qb, Qc);input Clk, D;
	output reg Qa, Qb, Qc;


	always @( * )
		if (Clk == 1'b1)
			Qa <= D;


	always @(posedge Clk)
		Qb <= D;


	always @(negedge Clk)
		Qc <= D;
endmodule
